import { useState } from "react";
import api from "../../api/axios";

export default function CreateStaff() {
  const [form, setForm] = useState({
    name: "",
    email: "",
    password: "",
    role: "staff", // staff or manager
  });

  const handleChange = (e) =>
    setForm({ ...form, [e.target.name]: e.target.value });

  const submit = async (e) => {
    e.preventDefault();
    try {
      const res = await api.post("/users/create", form); // admin only
      alert(`Created ${res.data.user.role}: ${res.data.user.email}`);
      setForm({ name: "", email: "", password: "", role: "staff" });
    } catch (err) {
      alert(err.response?.data?.message || "Failed to create user");
    }
  };

  return (
    <div style={{ maxWidth: 420, margin: "30px auto", padding: 16 }}>
      <h2>Create Staff / Manager</h2>

      <form onSubmit={submit}>
        <input
          name="name"
          placeholder="Name"
          value={form.name}
          onChange={handleChange}
          required
          style={{ width: "100%", padding: 10, marginTop: 10 }}
        />

        <input
          name="email"
          type="email"
          placeholder="Email"
          value={form.email}
          onChange={handleChange}
          required
          style={{ width: "100%", padding: 10, marginTop: 10 }}
        />

        <input
          name="password"
          type="password"
          placeholder="Temporary Password"
          value={form.password}
          onChange={handleChange}
          required
          style={{ width: "100%", padding: 10, marginTop: 10 }}
        />

        <select
          name="role"
          value={form.role}
          onChange={handleChange}
          style={{ width: "100%", padding: 10, marginTop: 10 }}
        >
          <option value="staff">Staff</option>
          <option value="manager">Manager</option>
        </select>

        <button type="submit" style={{ width: "100%", padding: 10, marginTop: 14 }}>
          Create
        </button>
      </form>
    </div>
  );
}
